from dataclasses import dataclass, field
from typing import Dict
import statistics


@dataclass
class DimensionScore:
    name: str
    weight: float      # points allocated out of 100
    max_raw: float     # maximum possible raw score (typically 5)
    sub_scores: Dict[str, float] = field(default_factory=dict)

    def raw_average(self) -> float:
        if not self.sub_scores:
            return 0.0
        return statistics.mean(self.sub_scores.values())

    def normalized_contribution(self) -> float:
        """This dimension's contribution to the 0-100 composite score."""
        return (self.raw_average() / self.max_raw) * self.weight


@dataclass
class IntakeProposal:
    proposal_id: str
    title: str
    requester: str
    dimensions: Dict[str, DimensionScore] = field(default_factory=dict)
    # reviewer_scores: {reviewer_id: {"dim.sub": raw_score}}
    reviewer_scores: Dict[str, Dict[str, float]] = field(default_factory=dict)

    def aggregate_reviewer_scores(self) -> None:
        """
        Populate dimension sub_scores from individual reviewer inputs.
        Uses committee median to suppress outlier inflation.
        """
        for dim_name, dim in self.dimensions.items():
            for sub_key in list(dim.sub_scores.keys()):
                key = f"{dim_name}.{sub_key}"
                vals = [
                    scores[key]
                    for scores in self.reviewer_scores.values()
                    if key in scores
                ]
                if vals:
                    dim.sub_scores[sub_key] = statistics.median(vals)

    def composite_score(self) -> float:
        return sum(d.normalized_contribution() for d in self.dimensions.values())

    def decision_band(self) -> str:
        score = self.composite_score()
        if score >= 80:
            return "AUTO_APPROVE"
        elif score >= 60:
            return "COMMITTEE_REVIEW"
        elif score >= 40:
            return "DEFER"
        return "REJECT"

    def score_report(self) -> str:
        lines = [
            f"Proposal:  {self.title} ({self.proposal_id})",
            f"Requester: {self.requester}",
            "-" * 58,
        ]
        for dim in self.dimensions.values():
            lines.append(
                f"  {dim.name:<28}  raw={dim.raw_average():.2f}/{dim.max_raw}"
                f"  contrib={dim.normalized_contribution():.1f}/{dim.weight}"
            )
        score = self.composite_score()
        lines += [
            "-" * 58,
            f"  Composite Score : {score:.1f} / 100",
            f"  Decision Band   : {self.decision_band()}",
        ]
        return "\n".join(lines)


# ── Example: financial-services loan underwriting assistant ─────────────────

def build_loan_underwriting_proposal() -> IntakeProposal:
    proposal = IntakeProposal(
        proposal_id="AI-2025-047",
        title="Automated Loan Underwriting Assistant",
        requester="retail-banking-ops",
        dimensions={
            "strategic_alignment": DimensionScore(
                name="Strategic Alignment", weight=25, max_raw=5,
                sub_scores={"okr_fit": 0.0, "exec_sponsorship": 0.0},
            ),
            "business_value": DimensionScore(
                name="Business Value", weight=25, max_raw=5,
                sub_scores={"roi_estimate": 0.0, "customer_impact": 0.0},
            ),
            "technical_feasibility": DimensionScore(
                name="Technical Feasibility", weight=20, max_raw=5,
                sub_scores={"data_readiness": 0.0, "team_capability": 0.0},
            ),
            "risk_profile": DimensionScore(
                name="Risk Profile", weight=15, max_raw=5,
                sub_scores={"regulatory_exposure": 0.0, "security_impact": 0.0},
            ),
            "urgency": DimensionScore(
                name="Urgency", weight=15, max_raw=5,
                sub_scores={"market_window": 0.0, "regulatory_deadline": 0.0},
            ),
        },
        reviewer_scores={
            "alice": {
                "strategic_alignment.okr_fit": 4, "strategic_alignment.exec_sponsorship": 5,
                "business_value.roi_estimate": 4, "business_value.customer_impact": 3,
                "technical_feasibility.data_readiness": 3, "technical_feasibility.team_capability": 4,
                "risk_profile.regulatory_exposure": 3, "risk_profile.security_impact": 3,
                "urgency.market_window": 3, "urgency.regulatory_deadline": 4,
            },
            "bob": {
                "strategic_alignment.okr_fit": 4, "strategic_alignment.exec_sponsorship": 5,
                "business_value.roi_estimate": 3, "business_value.customer_impact": 4,
                "technical_feasibility.data_readiness": 3, "technical_feasibility.team_capability": 3,
                "risk_profile.regulatory_exposure": 2, "risk_profile.security_impact": 3,
                "urgency.market_window": 3, "urgency.regulatory_deadline": 4,
            },
            "carol": {
                "strategic_alignment.okr_fit": 5, "strategic_alignment.exec_sponsorship": 5,
                "business_value.roi_estimate": 4, "business_value.customer_impact": 3,
                "technical_feasibility.data_readiness": 4, "technical_feasibility.team_capability": 4,
                "risk_profile.regulatory_exposure": 3, "risk_profile.security_impact": 2,
                "urgency.market_window": 4, "urgency.regulatory_deadline": 5,
            },
        },
    )
    proposal.aggregate_reviewer_scores()
    return proposal


if __name__ == "__main__":
    p = build_loan_underwriting_proposal()
    print(p.score_report())

